let{test,expect}=require("@playwright/test");test("Spanish version should have the correct content",async({page:t})=>{await t.goto("http://localhost:8001/es/"),await t.waitForSelector(".nav-menu");var e=await t.locator(".nav-menu a").nth(0).textContent(),a=await t.locator(".nav-menu a").nth(1).textContent(),n=await t.locator(".signup-button").textContent(),e=(console.log("Spanish texts:",{features:e,team:a,signUp:n}),await t.screenshot({path:"test-results/spanish-content.png"}),expect(e).toBe("Características"),expect(a).toBe("Equipo"),expect(n).toBe("Registrarse"),await t.evaluate(()=>document.documentElement.lang));expect(e).toBe("es")});